import{bV as s,aL as e,u as a,G as i}from"./chunks/framework.D_inzUUb.js";const c=JSON.parse('{"title":"FFmpeg 处理视频","description":"","frontmatter":{"title":"FFmpeg 处理视频","date":"2023-04-19T00:00:00.000Z","categories":["工具使用"],"tags":["FFmpeg","视频","多媒体"]},"headers":[],"relativePath":"posts/202304/19-ffmpeg-video.md","filePath":"posts/202304/19-ffmpeg-video.md","lastUpdated":1777371762000}'),d={name:"posts/202304/19-ffmpeg-video.md"};function p(h,t,n,l,o,r){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="ffmpeg-处理视频" tabindex="-1">FFmpeg 处理视频 <a class="header-anchor" href="#ffmpeg-处理视频" aria-label="Permalink to &quot;FFmpeg 处理视频&quot;">​</a></h1><h2 id="按时间分割视频" tabindex="-1">按时间分割视频 <a class="header-anchor" href="#按时间分割视频" aria-label="Permalink to &quot;按时间分割视频&quot;">​</a></h2><p>将视频按指定时长分割为多个片段：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;input.MP4&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -map</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -reset_timestamps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -segment_time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 60</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> segment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output_%03d.MP4</span></span></code></pre></div><p>参数说明：</p><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td><code>-c copy</code></td><td>直接复制流，不重新编码（速度快）</td></tr><tr><td><code>-map 0</code></td><td>映射所有流</td></tr><tr><td><code>-reset_timestamps 1</code></td><td>重置时间戳</td></tr><tr><td><code>-segment_time 60</code></td><td>每段时长 60 秒</td></tr><tr><td><code>-f segment</code></td><td>使用分段输出格式</td></tr></tbody></table><h2 id="关于视频分割后前导空白的问题" tabindex="-1">关于视频分割后前导空白的问题 <a class="header-anchor" href="#关于视频分割后前导空白的问题" aria-label="Permalink to &quot;关于视频分割后前导空白的问题&quot;">​</a></h2><p>像视频这样的进行压缩的，该技术仅将视频中发生更改的部分保存为帧，而不是每个帧的所有像素数据。</p><p>当您将视频分段时，通常遵循关键帧（I 帧）的规则，这些规则确保每个切割的片段都以 I 帧开头，因为 I 帧是关键帧，可以独立显示，因此 I 帧之间的 B 帧和 P 帧可以更轻松地进行解码。</p><p>当用于压缩视频的算法以帧差异的形式工作时，前媒体通常是通过差异编码技术导空白通常被包含在前一个 I 帧切割视频段的末尾和下一个 I 帧切割视频段的开头（因为它是从先前的帧中派生出来的）。因此，当您在第二段视频中开始播放时，您可能会看到空闲时间，这是因为之前的部分被包含在第一个视频片段中。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>使用 <code>-reset_timestamps 1</code> 参数可以重置时间戳来解决此问题，但可能会对部分视频的编辑和处理产生影响，请根据自己的需求谨慎使用。</p></div>',11)])])}const F=s(d,[["render",p]]);export{c as __pageData,F as default};
